import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  adminDashboard, adminPendingJobs, adminAllJobs,
  adminApproveJob, adminRejectJob, adminGetUsers, adminGetReports,
} from '../utils/api';
import { useAuth } from '../context/AuthContext';

const AdminDashboard = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [tab, setTab] = useState('overview');
  const [stats, setStats] = useState(null);
  const [pending, setPending] = useState([]);
  const [allJobs, setAllJobs] = useState([]);
  const [users, setUsers] = useState([]);
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [rejectReason, setRejectReason] = useState('');
  const [rejectTarget, setRejectTarget] = useState(null);

  useEffect(() => {
    const load = async () => {
      try {
        const [sRes, pRes] = await Promise.all([
          adminDashboard(),
          adminPendingJobs()
        ]);
        setStats(sRes.data);
        setPending(pRes.data);
      } catch {}
      setLoading(false);
    };
    load();
  }, []);

  const loadTab = async (t) => {
    setTab(t);
    try {
      if (t === 'all-jobs') setAllJobs((await adminAllJobs()).data);
      if (t === 'users') setUsers((await adminGetUsers()).data);
      if (t === 'reports') setReports((await adminGetReports()).data);
    } catch {}
  };

  const approve = async (id) => {
    await adminApproveJob(id);
    setPending(prev => prev.filter(j => j._id !== id));
  };

  const reject = async () => {
    if (!rejectTarget) return;
    await adminRejectJob(rejectTarget, rejectReason);
    setPending(prev => prev.filter(j => j._id !== rejectTarget));
    setRejectTarget(null);
    setRejectReason('');
  };

  if (!user?.isAdmin) {
    navigate('/admin-login', { replace: true });
    return null;
  }

  if (loading) {
    return <div className="loading"><div className="spinner" /></div>;
  }

  return (
    <div className="page">

      {/* 🔥 HEADER */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: 20
      }}>
        <h1 style={{
          fontFamily: 'var(--font-display)',
          fontSize: '1.4rem',
          fontWeight: 800
        }}>
          ⚙️ Admin Panel
        </h1>

        <button
          className="btn btn-sm btn-dark"
          onClick={() => { logout(); navigate('/admin-login'); }}
        >
          Logout
        </button>
      </div>

      {/* 🔥 TOP BUTTONS (your requirement) */}
      <div style={{
        display: 'flex',
        gap: 12,
        marginBottom: 20,
        flexWrap: 'wrap'
      }}>
        {[
          ['overview', '⏳ Pending'],
          ['all-jobs', '📋 All Jobs'],
          ['users', '👥 Users'],
          ['reports', '🚩 Reports']
        ].map(([t, label]) => (
          <button
            key={t}
            className={`btn btn-sm ${tab === t ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => loadTab(t)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* 🔥 STATS */}
      {stats && (
        <div className="admin-stats">
          {[
            { label: 'Total Users', value: stats.totalUsers, icon: '👥' },
            { label: 'Total Jobs', value: stats.totalJobs, icon: '📋' },
            { label: 'Pending', value: stats.pendingJobs, icon: '⏳' },
            { label: 'Active Jobs', value: stats.activeJobs, icon: '🟢' },
          ].map((s) => (
            <div key={s.label} className="stat-card">
              <div style={{ fontSize: '1.5rem' }}>{s.icon}</div>
              <span className="stat-number">{s.value}</span>
              <div className="stat-label">{s.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* 🔥 CONTENT */}
      {tab === 'overview' && (
        <>
          <div className="section-title">
            ⏳ Pending Approval ({pending.length})
          </div>

          {pending.length === 0 && (
            <div className="empty-state">
              <div className="empty-icon">🎉</div>
              <p>All caught up!</p>
            </div>
          )}

          {pending.map(job => (
            <div key={job._id} className="admin-job-card">
              <div style={{ fontWeight: 700 }}>{job.title}</div>

              <div className="admin-actions">
                <button className="btn btn-success btn-sm"
                  onClick={() => approve(job._id)}>
                  ✅ Approve
                </button>

                <button className="btn btn-danger btn-sm"
                  onClick={() => setRejectTarget(job._id)}>
                  ❌ Reject
                </button>
              </div>
            </div>
          ))}
        </>
      )}

      {tab === 'all-jobs' && (
        <div className="section-title">📋 All Jobs ({allJobs.length})</div>
      )}

      {tab === 'users' && (
        <div className="section-title">👥 Users ({users.length})</div>
      )}

      {tab === 'reports' && (
        <div className="section-title">🚩 Reports ({reports.length})</div>
      )}

      {/* Reject Modal */}
      {rejectTarget && (
        <div style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.6)',
          display: 'flex',
          alignItems: 'flex-end'
        }}>
          <div style={{
            background: '#fff',
            padding: 20,
            width: '100%'
          }}>
            <h3>Reject Job</h3>

            <select
              value={rejectReason}
              onChange={(e) => setRejectReason(e.target.value)}
            >
              <option value="">Select reason</option>
              <option>Spam</option>
              <option>Duplicate</option>
            </select>

            <button onClick={reject}>Confirm</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
